// =========================================================
// 1. GESTION DU FEED (Tous / Abonnements)
// =========================================================
function switchFeed(view) {
    // -- On récupère les éléments par leur ID --
    const container = document.getElementById('posts-container');
    const btnAll = document.getElementById('btn-all');
    const btnFollowing = document.getElementById('id-btn-following'); // <--- Vérifie cet ID !

    if (!container) return; // Sécurité si la div n'existe pas

    // -- Gestion visuelle de l'onglet actif --
    if (view === 'all') {
        btnAll.classList.add('active-tab');
        btnFollowing.classList.remove('active-tab');
    } else {
        btnFollowing.classList.add('active-tab');
        btnAll.classList.remove('active-tab');
    }

    // -- Appel AJAX pour recharger les posts --
    container.style.opacity = "0.3"; // Petit effet visuel pendant le chargement

    fetch(`ajax_get_posts.php?view=${view}`)
        .then(response => response.text())
        .then(html => {
            container.innerHTML = html; // On remplace le contenu du container
            container.style.opacity = "1";
        })
        .catch(err => {
            console.error("Erreur AJAX :", err);
            container.style.opacity = "1";
        });
}

// ===== end of the code zone generated by Gemini ===


// =========================================================
// 2. GESTION DES LIKES
// =========================================================
function toggleLike(postId, element) {
    const formData = new FormData();
    formData.append('post_id', postId);

    // -- On envoie la requête de modification au PHP --
    fetch('ajax_toggle_like.php', {
        method: 'POST',
        body: formData
    })
    .then(response => response.json())
    .then(data => {
        // -- On cible l'image du coeur et le compteur à l'intérieur du bouton cliqué --
        const img = element.querySelector('img');
        const countSpan = element.querySelector('span');
        let currentCount = parseInt(countSpan.innerText);

        // -- Mise à jour visuelle selon la réponse du serveur --
        if (data.status === 'liked') {
            img.src = 'img/icons/Heart Full.png'; // Le coeur devient rouge
            countSpan.innerText = currentCount + 1;
        } else {
            img.src = 'img/icons/Heart Hollow.png'; // Le coeur redevient vide
            countSpan.innerText = currentCount - 1;
        }
    })
    .catch(err => console.error("Erreur Like:", err));
}

// =========================================================
// 3. GESTION DES COMMENTAIRES
// =========================================================

// -- Affiche ou cache la zone de saisie du commentaire --
function toggleCommentForm(postId) {
    const box = document.getElementById(`comment-box-${postId}`);
    box.style.display = box.style.display === 'none' ? 'block' : 'none';
}

// ===== begin of the code zone generated by Gemini ===
// -- Envoie un nouveau commentaire sans recharger la page --
function sendComment(postId) {
    const input = document.getElementById(`input-comment-${postId}`);
    const content = input.value;

    if (content.trim() === "") return; // Bloque l'envoi si vide

    const formData = new FormData();
    formData.append('post_id', postId);
    formData.append('content', content);

    fetch('ajax_add_comment.php', {
        method: 'POST',
        body: formData
    })
    .then(response => response.json())
    .then(data => {
        if (data.status === 'success') {
            // -- Créer et insérer le nouveau commentaire en haut de la liste --
            const list = document.getElementById(`comments-list-${postId}`);
            const newComment = document.createElement('div');
            newComment.innerHTML = `<strong>${data.user}:</strong> ${data.content}`;
            newComment.style.fontSize = "13px";
            newComment.style.marginTop = "5px";
            list.prepend(newComment);

            // -- Vider le champ de saisie et incrémenter le compteur visuel --
            input.value = "";
            const count = document.getElementById(`comment-count-${postId}`);
            count.innerText = parseInt(count.innerText) + 1;
        }
    });
}
// ===== end of the code zone generated by Gemini ===

// -- Charge l'historique complet des commentaires au clic sur "Show more" --
function loadAllComments(postId, btn) {
    // Appel du script PHP qui génère le HTML complet des commentaires
    fetch(`ajax_get_all_comments.php?post_id=${postId}`)
        .then(response => response.text())
        .then(html => {
            const list = document.getElementById(`comments-list-${postId}`);
            list.innerHTML = html; // On écrase l'aperçu avec la liste complète
            btn.style.display = 'none'; // On masque le bouton une fois tout chargé
        })
        .catch(err => console.error("Erreur chargement commentaires:", err));
}

