// -- Variable globale de verrouillage pour empêcher le multi-clic/double envoi --
if (typeof isSubmitting === 'undefined') {
    var isSubmitting = false;
}

// ===== begin of the code zone generated by Gemini ===

// -- Initialisation des événements au chargement de la page --
document.addEventListener('DOMContentLoaded', function() {
    
    // -- Liaison : Clic sur l'icône photo ouvre le sélecteur de fichier invisible --
    const photoIcon = document.querySelector('.create-post-icons'); 
    const fileInput = document.getElementById('postMedia'); 

    if (photoIcon && fileInput) {
        photoIcon.addEventListener('click', () => {
            fileInput.click(); 
        });
    }

    // -- Assignation des événements d'ouverture/fermeture de la modale --
    const openButton = document.getElementById('openPostModalGlobal');
    const closeButton = document.getElementById('closePostModal');
    const cancelButton = document.getElementById('cancelPost');
    const form = document.getElementById('createPostForm');

    if (openButton) openButton.addEventListener('click', openPostModal);
    if (closeButton) closeButton.addEventListener('click', closePostModal);
    if (cancelButton) {
        cancelButton.addEventListener('click', function() { 
            closePostModal(); 
            resetCreatePostForm(); 
        });
    }

    // -- Soumission du formulaire de publication via AJAX --
    if (form) {
        form.addEventListener('submit', function(event) {
            event.preventDefault(); // On bloque le rechargement classique

            // -- Sécurité : On bloque si une requête est déjà en cours --
            if (isSubmitting) return;

            const contentInput = document.getElementById('postContent');
            const content = contentInput.value.trim();
            const submitBtn = form.querySelector('.create-post-submit');

            if (!content) {
                displayPostMessage('Le contenu est requis.', true);
                return;
            }

            // -- Verrouillage de l'interface pendant l'upload --
            isSubmitting = true;
            submitBtn.disabled = true;
            submitBtn.innerText = "Envoi...";
            submitBtn.style.opacity = "0.5";

            const formData = new FormData(form);

            fetch('ajax_create_post.php', {
                method: 'POST',
                body: formData
            })
            .then(response => response.json())
            .then(data => {
                if (data.success) {
                    displayPostMessage('Publication réussie !', false);
                    resetCreatePostForm();
                    
                    setTimeout(() => {
                        closePostModal();
                        isSubmitting = false; // On libère le verrou
                        
                        // -- RESTE SUR LA PAGE : on recharge la page actuelle --
                        // pour afficher le nouveau post dans le feed
                        location.reload(); 
                    }, 500);
                } else {
                    alert(data.error);
                    // -- Déverrouillage en cas de retour d'erreur du serveur --
                    isSubmitting = false;
                    submitBtn.disabled = false;
                    submitBtn.innerText = "Publier";
                    submitBtn.style.opacity = "1";
                }
            })
            .catch(err => {
                console.error('Erreur :', err);
                // -- Déverrouillage en cas d'erreur réseau --
                isSubmitting = false;
                submitBtn.disabled = false;
                submitBtn.innerText = "Publier";
                submitBtn.style.opacity = "1";
            });
        });
    }
});

// ===== end of the code zone generated by Gemini ===
